// Extraer mensaje entrante de Twilio WhatsApp
const body = $input.first().json.body;
const from = body.From || '';
const msgBody = body.Body || '';
const phone = from.replace('whatsapp:', '');

return [{
  json: {
    phone: phone,
    message: msgBody,
    timestamp: new Date().toISOString()
  }
}];

// Detectar si hay una reserva completa en la respuesta
const aiResponse = $input.first().json.message.content || '';
const match = aiResponse.match(/\[RESERVA_COMPLETA:(\{.*?\})]/);

let reservaData = null;
let cleanResponse = aiResponse.replace(/\[RESERVA_COMPLETA:.*?\]/, '').trim();

if (match) {
  try {
    reservaData = JSON.parse(match[1]);
  } catch(e) {
    reservaData = null;
  }
}

return [{
  json: {
    response: cleanResponse,
    hasBooking: reservaData !== null,
    bookingData: reservaData,
    phone: $('Parsear Mensaje').first().json.phone
  }
}];

